package com.example.offlineshapealarm.alarm
import android.app.*; import android.content.*; import android.os.Build; import androidx.core.app.NotificationCompat; import com.example.offlineshapealarm.R
const val CHANNEL_ID="shape_alarm_active"; const val NOTIFICATION_ID=7301
fun createAlarmChannel(context: Context){ if(Build.VERSION.SDK_INT>=26){ val ch=NotificationChannel(CHANNEL_ID,"Active alarms",NotificationManager.IMPORTANCE_HIGH); ch.description="Foreground notifications for ringing alarms"; ch.setSound(null,null); ch.enableVibration(false); ch.lockscreenVisibility=android.app.Notification.VISIBILITY_PUBLIC; context.getSystemService(NotificationManager::class.java).createNotificationChannel(ch) } }
fun alarmActivityIntent(context: Context, payload: AlarmPayload): PendingIntent { val i=Intent(context, AlarmActivity::class.java).putExtra("alarmId",payload.alarmId).putExtra("label",payload.label).putExtra("challengeType",payload.challengeType).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP); return PendingIntent.getActivity(context, payload.requestCode+100000, i, PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE) }
fun activeNotification(context: Context, payload: AlarmPayload): android.app.Notification { createAlarmChannel(context); val open=alarmActivityIntent(context,payload); return NotificationCompat.Builder(context, CHANNEL_ID).setSmallIcon(R.mipmap.ic_launcher).setContentTitle(payload.label.ifBlank{"Alarm"}).setContentText("Hold to dismiss in the alarm screen.").setCategory(NotificationCompat.CATEGORY_ALARM).setPriority(NotificationCompat.PRIORITY_MAX).setOngoing(true).setVisibility(NotificationCompat.VISIBILITY_PUBLIC).setContentIntent(open).setFullScreenIntent(open,true).build() }
